/**
 * Export to Excel with better formatting (uses HTML table trick)
 * This creates a proper Excel file that can be opened in Excel
 */
function exportToExcelHTML(data, filename, columns, title) {
  // Create HTML table
  const headers = columns.map(col => col.header).join("</th><th>");
  const rows = data.map(item => `<tr>${columns.map(col => {
    const value = col.accessor(item);
    const formatted = col.format ? col.format(value, item) : value;
    return `<td>${formatted ?? ""}</td>`;
  }).join("")}</tr>`).join("");
  const now = new Date().toLocaleDateString("ar-SA-u-nu-latn");
  const htmlContent = `
    <html xmlns:x="urn:schemas-microsoft-com:office:excel" dir="rtl">
      <head>
        <meta charset="UTF-8">
        <style>
          table { 
            border-collapse: collapse; 
            width: 100%; 
            font-family: Arial, sans-serif;
            direction: rtl;
          }
          th { 
            background-color: #0f172a; 
            color: white; 
            padding: 12px; 
            text-align: right;
            border: 1px solid #ddd;
            font-weight: bold;
          }
          td { 
            padding: 10px; 
            border: 1px solid #ddd;
            text-align: right;
          }
          tr:nth-child(even) { 
            background-color: #f9f9f9; 
          }
          .header {
            margin-bottom: 20px;
            text-align: center;
          }
          .header h1 {
            color: #0f172a;
            margin: 10px 0;
          }
          .header p {
            color: #666;
            margin: 5px 0;
          }
        </style>
      </head>
      <body>
        <div class="header">
          <h1>${title}</h1>
          <p>تاريخ الإنشاء: ${now}</p>
        </div>
        <table>
          <thead>
            <tr><th>${headers}</th></tr>
          </thead>
          <tbody>
            ${rows}
          </tbody>
        </table>
      </body>
    </html>
  `;
  const blob = new Blob([htmlContent], {
    type: "application/vnd.ms-excel;charset=utf-8;"
  });
  downloadBlob(blob, `${filename}.xls`);
}

