function useItemsData(isAuthenticated) {
  const queryClient = useQueryClient();
  const {
    data: items = [],
    isLoading
  } = useQuery({
    queryKey: ["items"],
    queryFn: async () => {
      const response = await adminFetch("/api/items");
      if (!response.ok) throw new Error("Failed to fetch items");
      return response.json();
    },
    enabled: isAuthenticated
  });
  const {
    data: branches = []
  } = useQuery({
    queryKey: ["branches"],
    queryFn: async () => {
      const response = await adminFetch("/api/branches");
      if (!response.ok) throw new Error("Failed to fetch branches");
      return response.json();
    },
    enabled: isAuthenticated
  });
  const createMutation = useMutation({
    mutationFn: async data => {
      console.log("Creating item with data:", data);
      const response = await adminFetch("/api/items", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(data)
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Failed to create item");
      }
      return response.json();
    },
    onSuccess: data => {
      console.log("Item created successfully:", data);
      queryClient.invalidateQueries({
        queryKey: ["items"]
      });
    },
    onError: error => {
      console.error("Failed to create item:", error);
    }
  });
  const updateMutation = useMutation({
    mutationFn: async data => {
      console.log("Updating item with data:", data);
      const response = await adminFetch("/api/items", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(data)
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Failed to update item");
      }
      return response.json();
    },
    onSuccess: data => {
      console.log("Item updated successfully:", data);
      queryClient.invalidateQueries({
        queryKey: ["items"]
      });
    },
    onError: error => {
      console.error("Failed to update item:", error);
    }
  });
  const deleteMutation = useMutation({
    mutationFn: async id => {
      const response = await adminFetch("/api/items", {
        method: "DELETE",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          id
        })
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Failed to delete item");
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["items"]
      });
    }
  });
  const batchInventoryMutation = useMutation({
    mutationFn: async ({
      ids,
      show_in_inventory
    }) => {
      const response = await adminFetch("/api/items/batch-inventory", {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          ids,
          show_in_inventory
        })
      });
      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Failed to batch update items");
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["items"]
      });
    },
    onError: error => {
      console.error("Failed to batch update items:", error);
    }
  });
  return {
    items,
    branches,
    isLoading,
    createMutation,
    updateMutation,
    deleteMutation,
    batchInventoryMutation
  };
}

function useItemForm() {
  const [formData, setFormData] = useState({
    name: "",
    name_en: "",
    description: "",
    min_stock_threshold: 10,
    is_active: true,
    unit: "حبة",
    category_id: null,
    cost: "",
    show_in_inventory: true,
    linked_green_bean_id: null
  });
  const [editingItem, setEditingItem] = useState(null);
  const resetForm = () => {
    setFormData({
      name: "",
      name_en: "",
      description: "",
      min_stock_threshold: 10,
      is_active: true,
      unit: "حبة",
      category_id: null,
      cost: "",
      show_in_inventory: true,
      linked_green_bean_id: null
    });
    setEditingItem(null);
  };
  const loadItem = item => {
    setEditingItem(item);
    const showInInventory = item.show_in_inventory !== false;
    setFormData({
      name: item.name,
      name_en: item.name_en || "",
      description: item.description || "",
      min_stock_threshold: item.min_stock_threshold || 10,
      is_active: showInInventory,
      unit: item.unit || "حبة",
      category_id: item.category_id || null,
      cost: item.cost != null ? item.cost : "",
      show_in_inventory: showInInventory,
      linked_green_bean_id: item.linked_green_bean_id || null
    });
  };

  // Wrap setFormData to keep is_active in sync with show_in_inventory
  const setFormDataSynced = valueOrUpdater => {
    setFormData(prev => {
      const next = typeof valueOrUpdater === "function" ? valueOrUpdater(prev) : valueOrUpdater;
      // Sync is_active to match show_in_inventory
      if (next.show_in_inventory !== undefined) {
        return {
          ...next,
          is_active: next.show_in_inventory
        };
      }
      return next;
    });
  };
  return {
    formData,
    setFormData: setFormDataSynced,
    editingItem,
    resetForm,
    loadItem
  };
}

function useItemCategories(enabled = true) {
  const queryClient = useQueryClient();
  const {
    data: categories = [],
    isLoading,
    error
  } = useQuery({
    queryKey: ["item-categories"],
    queryFn: async () => {
      const response = await adminFetch("/api/item-categories");
      if (!response.ok) {
        throw new Error(`When fetching /api/item-categories, the response was [${response.status}] ${response.statusText}`);
      }
      return response.json();
    },
    enabled
  });
  const createMutation = useMutation({
    mutationFn: async ({
      name,
      name_en
    }) => {
      const response = await adminFetch("/api/item-categories", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          name,
          name_en
        })
      });
      if (!response.ok) {
        let message = "Failed to create category";
        try {
          const errorBody = await response.json();
          message = errorBody?.error || message;
        } catch {
          // ignore
        }
        throw new Error(message);
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["item-categories"]
      });
    }
  });
  const updateMutation = useMutation({
    mutationFn: async ({
      id,
      name,
      name_en
    }) => {
      const response = await adminFetch("/api/item-categories", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          id,
          name,
          name_en
        })
      });
      if (!response.ok) {
        let message = "Failed to update category";
        try {
          const errorBody = await response.json();
          message = errorBody?.error || message;
        } catch {
          // ignore
        }
        throw new Error(message);
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["item-categories"]
      });
    }
  });
  return {
    categories,
    isLoading,
    error,
    createMutation,
    updateMutation
  };
}

