function getTotalStock(item) {
  const list = Array.isArray(item?.branch_stock) ? item.branch_stock : [];
  return list.reduce((sum, s) => {
    const qty = Number(s?.quantity || 0);
    return sum + (Number.isFinite(qty) ? qty : 0);
  }, 0);
}
