function useOperationsData(isAuthenticated) {
  const queryClient = useQueryClient();
  const {
    data: operations,
    isLoading
  } = useQuery({
    queryKey: ["inventory-operations"],
    queryFn: async () => {
      const response = await adminFetch("/api/inventory-operations");
      if (!response.ok) throw new Error("Failed to fetch operations");
      return response.json();
    },
    enabled: isAuthenticated
  });
  const {
    data: branches
  } = useQuery({
    queryKey: ["branches"],
    queryFn: async () => {
      const response = await adminFetch("/api/branches");
      if (!response.ok) throw new Error("Failed to fetch branches");
      return response.json();
    },
    enabled: isAuthenticated
  });
  const deleteMutation = useMutation({
    mutationFn: async operationId => {
      const response = await adminFetch(`/api/inventory-operations?id=${operationId}`, {
        method: "DELETE"
      });
      if (!response.ok) {
        const data = await response.json().catch(() => ({}));
        throw new Error(data.error || "فشل في حذف العملية");
      }
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["inventory-operations"]
      });
      queryClient.invalidateQueries({
        queryKey: ["items-summary"]
      });
      queryClient.invalidateQueries({
        queryKey: ["low-stock"]
      });
      queryClient.invalidateQueries({
        queryKey: ["purchase-receipts"]
      });
    }
  });
  return {
    operations,
    branches,
    isLoading,
    deleteMutation
  };
}

function useOperationsFilters(operations) {
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedBranch, setSelectedBranch] = useState("");
  const [selectedType, setSelectedType] = useState("");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [showFilters, setShowFilters] = useState(false);
  const filteredOperations = useMemo(() => {
    return operations?.filter(op => {
      if (searchQuery) {
        const q = searchQuery.toLowerCase();
        const matchNumber = op.inventory_number?.toLowerCase().includes(q);
        const matchReceipt = op.receipt_item_name?.toLowerCase().includes(q);
        if (!matchNumber && !matchReceipt) {
          return false;
        }
      }
      if (selectedBranch && op.branch_id !== parseInt(selectedBranch)) {
        return false;
      }
      if (selectedType && op.inventory_type !== selectedType) {
        return false;
      }
      const filterDate = op.operation_date || op.created_at;
      if (dateFrom) {
        const fromDate = new Date(dateFrom);
        fromDate.setHours(0, 0, 0, 0);
        if (new Date(filterDate) < fromDate) {
          return false;
        }
      }
      if (dateTo) {
        const toDate = new Date(dateTo);
        toDate.setHours(23, 59, 59, 999);
        if (new Date(filterDate) > toDate) {
          return false;
        }
      }
      return true;
    });
  }, [operations, searchQuery, selectedBranch, selectedType, dateFrom, dateTo]);
  const clearFilters = () => {
    setSearchQuery("");
    setSelectedBranch("");
    setSelectedType("");
    setDateFrom("");
    setDateTo("");
  };
  const hasActiveFilters = searchQuery || selectedBranch || selectedType || dateFrom || dateTo;
  return {
    searchQuery,
    setSearchQuery,
    selectedBranch,
    setSelectedBranch,
    selectedType,
    setSelectedType,
    dateFrom,
    setDateFrom,
    dateTo,
    setDateTo,
    showFilters,
    setShowFilters,
    filteredOperations,
    clearFilters,
    hasActiveFilters
  };
}

function useOperationDetails() {
  const [selectedOperation, setSelectedOperation] = useState(null);
  const {
    data: operationDetails
  } = useQuery({
    queryKey: ["operation-details", selectedOperation?.id],
    queryFn: async () => {
      const response = await adminFetch(`/api/inventory-operations?id=${selectedOperation.id}`);
      if (!response.ok) throw new Error("Failed to fetch operation details");
      return response.json();
    },
    enabled: !!selectedOperation
  });
  return {
    selectedOperation,
    setSelectedOperation,
    operationDetails
  };
}

function nowLocalDatetime$2() {
  const d = new Date();
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  const hh = String(d.getHours()).padStart(2, "0");
  const min = String(d.getMinutes()).padStart(2, "0");
  return `${yyyy}-${mm}-${dd}T${hh}:${min}`;
}
